const fs = require('fs');
const path = require('path');

/*
 * 生成 file:// 可直接运行的 js/bundle.js。
 *
 * 源码使用 ES Module 写法，直接双击 index.html 时部分浏览器会因为本地文件
 * 的模块跨文件加载限制而失败。所以这里按固定顺序把运行时模块合并成一个普通
 * IIFE 脚本，index.html 只需要引入 bundle.js。
 */
const root = path.resolve(__dirname, '..');

// 打包顺序很重要：配置和工具必须在效果类之前，App 必须最后启动。
const files = [
    'js/config/config.js',
    'js/utils/heartPath.js',
    'js/utils/userConfigStore.js',
    'js/resourceLoader.js',
    'js/effects/BackgroundMusicEffect.js',
    'js/effects/Heart.js',
    'js/effects/FallingHeartsEffect.js',
    'js/effects/HeartRateEffect.js',
    'js/effects/HeartEffect.js',
    'js/effects/SecondHeartEffect.js',
    'js/effects/ECGEffect.js',
    'js/effects/NewPixelatedPreview.js',
    'js/effects/NewPhotoWall.js',
    'js/effects/ProposalMessageEffect.js',
    'js/app.js'
];

/*
 * 轻量转换 ES Module 语法。
 *
 * 所有模块最终进入同一个函数作用域，因此 import 行可以删除，export 关键字
 * 可以去掉；源码里的类名、常量名和单例仍然能在后续拼接片段中被访问。
 */
function transformModule(source) {
    return source
        .replace(/^\s*import\s+[^;]+;\s*$/gm, '')
        .replace(/^\s*export\s+/gm, '');
}

// 给每个片段加上源文件标记，方便调试 bundle.js 时快速定位回原始文件。
const chunks = files.map(file => {
    const absolutePath = path.join(root, file);
    const source = fs.readFileSync(absolutePath, 'utf8');
    return `\n// ${file}\n${transformModule(source)}\n`;
});

// 用严格模式包一层 IIFE，避免变量泄漏到全局作用域。
const bundle = `// Generated by scripts/build-bundle.js. Do not edit by hand.\n(() => {\n'use strict';\n${chunks.join('\n')}\n})();\n`;

// bundle.js 是生成产物，不手动维护；每次源码变化后重新运行本脚本即可。
fs.writeFileSync(path.join(root, 'js/bundle.js'), bundle, 'utf8');
console.log(`Bundled ${files.length} files into js/bundle.js`);
